cat > /tmp/check_access.cpp << 'EOF'
#include <iostream>
#include <csignal>
#include <csetjmp>
using namespace std;

int x[] = { 1, 2, 3, 4, 5 };
jmp_buf jump_buffer;

void signal_handler(int sig) {
    cout << "Caught signal " << sig << endl;
    longjmp(jump_buffer, 1);
}

void foo(int n, float b) {
  int index = n * 10000;
  if (setjmp(jump_buffer) == 0) {
    signal(SIGSEGV, signal_handler);
    signal(SIGBUS, signal_handler);
    cout << "TEST " << x[index] << endl;
  } else {
    cout << "Access to x[" << index << "] caused a crash!" << endl;
  }
}

int main()
{
  for (auto i = 0; i < 10; i++) {
    foo(i, 1.0);
  }
  return 0;
}
EOF
clang++ -g -O0 /tmp/check_access.cpp -o /tmp/check_access && /tmp/check_access 2>&1
